# EVOLVE-BLOCK-START
import networkx as nx
import json
import os
import pandas as pd
from typing import Dict, List


def search_algorithm(src, dsts, G, num_partitions):
    """
    Iterative Steiner tree optimization: start from shortest paths, then
    iteratively re-route destinations through shared tree edges (zero cost)
    to minimize total unique edge cost in the broadcast tree.
    """
    h = G.copy()
    h.remove_edges_from(list(h.in_edges(src)) + list(nx.selfloop_edges(h)))

    # Remove edges with None cost
    none_cost_edges = [(u, v) for u, v, d in h.edges(data=True) if d.get('cost') is None]
    h.remove_edges_from(none_cost_edges)

    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Step 1: Get initial shortest paths for each destination
    dst_paths = {}
    for dst in dsts:
        try:
            path = nx.dijkstra_path(h, src, dst, weight='cost')
            dst_paths[dst] = path
        except nx.NetworkXNoPath:
            pass

    if not dst_paths:
        return bc_topology

    # Step 2: Iterative refinement - repeatedly re-route through shared edges
    for iteration in range(5):
        improved = False

        # Build current tree edge set
        tree_edges = set()
        for path in dst_paths.values():
            for i in range(len(path) - 1):
                tree_edges.add((path[i], path[i + 1]))

        # Calculate current total tree cost
        current_cost = sum(h[u][v]['cost'] for u, v in tree_edges if h.has_edge(u, v))

        # For each destination, try to find a cheaper path using tree edges as free
        for dst in dsts:
            if dst not in dst_paths:
                continue

            old_path = dst_paths[dst]

            # Edges used ONLY by this destination
            other_edges = set()
            for other_dst, other_path in dst_paths.items():
                if other_dst == dst:
                    continue
                for i in range(len(other_path) - 1):
                    other_edges.add((other_path[i], other_path[i + 1]))

            # Create modified graph: edges used by other dsts are free
            h_mod = h.copy()
            for u, v in other_edges:
                if h_mod.has_edge(u, v):
                    h_mod[u][v]['cost'] = 0.0

            try:
                new_path = nx.dijkstra_path(h_mod, src, dst, weight='cost')
            except nx.NetworkXNoPath:
                continue

            # Calculate marginal cost of new path (cost of edges NOT in other_edges)
            new_marginal = sum(
                h[new_path[i]][new_path[i + 1]]['cost']
                for i in range(len(new_path) - 1)
                if (new_path[i], new_path[i + 1]) not in other_edges
            )
            old_marginal = sum(
                h[old_path[i]][old_path[i + 1]]['cost']
                for i in range(len(old_path) - 1)
                if (old_path[i], old_path[i + 1]) not in other_edges
            )

            if new_marginal < old_marginal - 1e-9:
                dst_paths[dst] = new_path
                improved = True

        if not improved:
            break

    # Step 3: Try adding relay nodes that could reduce cost
    # For each pair of destinations, check if routing one through the other's path helps
    # (This is already handled by the iterative refinement above, but let's also try
    # connecting destinations through intermediate non-terminal nodes)

    # Final pass: verify and build topology
    tree_edges = set()
    for path in dst_paths.values():
        for i in range(len(path) - 1):
            tree_edges.add((path[i], path[i + 1]))

    # One more optimization: try to find paths through ANY tree node
    # using a modified Dijkstra where all tree edges are free
    final_improved = True
    for _ in range(3):
        if not final_improved:
            break
        final_improved = False

        # Rebuild tree edges
        tree_edges = set()
        for path in dst_paths.values():
            for i in range(len(path) - 1):
                tree_edges.add((path[i], path[i + 1]))

        h_mod = h.copy()
        for u, v in tree_edges:
            if h_mod.has_edge(u, v):
                h_mod[u][v]['cost'] = 0.0

        for dst in dsts:
            if dst not in dst_paths:
                continue
            old_path = dst_paths[dst]
            try:
                new_path = nx.dijkstra_path(h_mod, src, dst, weight='cost')
            except nx.NetworkXNoPath:
                continue

            # Check if new path adds less cost
            new_added = sum(
                h[new_path[i]][new_path[i + 1]]['cost']
                for i in range(len(new_path) - 1)
                if (new_path[i], new_path[i + 1]) not in tree_edges
            )
            # Old path: all its edges are in tree_edges, so 0 added cost
            # But removing old path might free up some edges
            # Check if any old edges are exclusively used by this dst
            old_exclusive = set()
            for i in range(len(old_path) - 1):
                edge = (old_path[i], old_path[i + 1])
                exclusive = True
                for other_dst, other_path in dst_paths.items():
                    if other_dst == dst:
                        continue
                    for j in range(len(other_path) - 1):
                        if (other_path[j], other_path[j + 1]) == edge:
                            exclusive = False
                            break
                    if not exclusive:
                        break
                if exclusive:
                    old_exclusive.add(edge)

            old_freed = sum(h[u][v]['cost'] for u, v in old_exclusive)

            # Net benefit: old_freed - new_added
            if new_added < old_freed - 1e-9:
                dst_paths[dst] = new_path
                final_improved = True
                # Update tree edges for subsequent iterations in this pass
                tree_edges = set()
                for path in dst_paths.values():
                    for i in range(len(path) - 1):
                        tree_edges.add((path[i], path[i + 1]))
                h_mod = h.copy()
                for u, v in tree_edges:
                    if h_mod.has_edge(u, v):
                        h_mod[u][v]['cost'] = 0.0

    # Build the broadcast topology
    for dst in dsts:
        if dst not in dst_paths:
            continue
        path = dst_paths[dst]
        for i in range(len(path) - 1):
            s, t = path[i], path[i + 1]
            edge_data = G[s][t] if G.has_edge(s, t) else h[s][t]
            for j in range(num_partitions):
                bc_topology.append_dst_partition_path(dst, j, [s, t, edge_data])

    return bc_topology


class SingleDstPath(Dict):
    partition: int
    edges: List[List]  # [[src, dst, edge data]]


class BroadCastTopology:
    def __init__(self, src: str, dsts: List[str], num_partitions: int = 4, paths: Dict[str, SingleDstPath] = None):
        self.src = src  # single str
        self.dsts = dsts  # list of strs
        self.num_partitions = num_partitions

        # dict(dst) --> dict(partition) --> list(nx.edges)
        # example: {dst1: {partition1: [src->node1, node1->dst1], partition 2: [src->dst1]}}
        if paths is not None:
            self.paths = paths
            self.set_graph()
        else:
            self.paths = {dst: {str(i): None for i in range(num_partitions)} for dst in dsts}

    def get_paths(self):
        print(f"now the set path is: {self.paths}")
        return self.paths

    def set_num_partitions(self, num_partitions: int):
        self.num_partitions = num_partitions

    def set_dst_partition_paths(self, dst: str, partition: int, paths: List[List]):
        """
        Set paths for partition = partition to reach dst
        """
        partition = str(partition)
        self.paths[dst][partition] = paths

    def append_dst_partition_path(self, dst: str, partition: int, path: List):
        """
        Append path for partition = partition to reach dst
        """
        partition = str(partition)
        if self.paths[dst][partition] is None:
            self.paths[dst][partition] = []
        self.paths[dst][partition].append(path)

def make_nx_graph(cost_path=None, throughput_path=None, num_vms=1):
    """
    Default graph with capacity constraints and cost info
    nodes: regions, edges: links
    per edge:
        throughput: max tput achievable (gbps)
        cost: $/GB
        flow: actual flow (gbps), must be < throughput, default = 0
    """
    # Use relative path from this file's location
    current_dir = os.path.dirname(os.path.abspath(__file__))

    if cost_path is None:
        cost = pd.read_csv(os.path.join(current_dir, "profiles/cost.csv"))
    else:
        cost = pd.read_csv(cost_path)

    if throughput_path is None:
        throughput = pd.read_csv(os.path.join(current_dir, "profiles/throughput.csv"))
    else:
        throughput = pd.read_csv(throughput_path)

    G = nx.DiGraph()
    for _, row in throughput.iterrows():
        if row["src_region"] == row["dst_region"]:
            continue
        G.add_edge(row["src_region"], row["dst_region"], cost=None, throughput=num_vms * row["throughput_sent"] / 1e9)

    for _, row in cost.iterrows():
        if row["src"] in G and row["dest"] in G[row["src"]]:
            G[row["src"]][row["dest"]]["cost"] = row["cost"]

    # some pairs not in the cost grid
    no_cost_pairs = []
    for edge in G.edges.data():
        src, dst = edge[0], edge[1]
        if edge[-1]["cost"] is None:
            no_cost_pairs.append((src, dst))
    print("Unable to get costs for: ", no_cost_pairs)

    return G


# EVOLVE-BLOCK-END

# Helper functions that won't be evolved
def create_broadcast_topology(src: str, dsts: List[str], num_partitions: int = 4):
    """Create a broadcast topology instance"""
    return BroadCastTopology(src, dsts, num_partitions)

def run_search_algorithm(src: str, dsts: List[str], G, num_partitions: int):
    """Run the search algorithm and return the topology"""
    return search_algorithm(src, dsts, G, num_partitions)

